select p.id, p.site_id, p.name, p.platform_type, p.api_endpoint, p.api_key, p.api_secret, p.model_name, p.available_models, p.category_id, p.config, p.max_tokens, p.temperature, p.rate_limit, p.cost_per_1k_tokens, p.is_default, p.status, p.del_flag, p.create_by, p.create_time, p.update_by, p.update_time, p.remark, c.name as category_name, c.icon as category_icon, -- 统一的可见性状态： -- 1. 自有配置（site_id = 当前网站）：优先使用关联表的is_visible（如果存在），否则使用配置本身的status -- 2. 用户默认站点（site_id = personalSiteId）： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站配置：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN p.site_id = #{siteId} THEN IFNULL(incl.is_visible, p.status) WHEN p.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, -- 关联来源标识：own(自己的) | default(默认配置) | shared(其他网站分享) CASE WHEN p.site_id = #{siteId} THEN 'own' WHEN p.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN p.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN 1 ELSE 0 END as is_excluded, (select count(*) from gb_site_ai_platform_relations r2 where r2.ai_platform_id = p.id AND r2.relation_type = 'include') as related_sites_count, (select count(*) from gb_site_ai_platform_relations r3 where r3.ai_platform_id = p.id AND r3.relation_type = 'exclude') as excluded_sites_count from gb_ai_platforms p left join gb_categories c on p.category_id = c.id and c.del_flag = '0' -- 左连接正向关联（include） LEFT JOIN gb_site_ai_platform_relations incl ON p.id = incl.ai_platform_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_ai_platform_relations excl ON p.id = excl.ai_platform_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
p.del_flag = '0'
AND ( p.site_id = #{siteId}
OR p.site_id = #{params.personalSiteId}
OR (p.site_id != #{siteId}
AND p.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) and p.category_id = #{categoryId} and p.name like concat('%', #{name}, '%') and p.platform_type = #{platformType} and p.is_default = #{isDefault} and p.status = #{status}
order by p.is_default desc, p.create_time desc

select p.*, 
       c.name as category_name,
       c.icon as category_icon,
       (select count(*) from gb_site_ai_platform_relations r where r.ai_platform_id = p.id AND r.relation_type = 'include') as related_sites_count,
       (select count(*) from gb_site_ai_platform_relations r where r.ai_platform_id = p.id AND r.relation_type = 'exclude') as excluded_sites_count
from gb_ai_platforms p
left join gb_categories c on p.category_id = c.id and c.del_flag = '0'

    p.del_flag = '0'



            and (p.site_id = #{siteId} OR p.site_id = #{params.personalSiteId})



            and p.site_id = #{siteId}



            and p.site_id = #{params.personalSiteId}


            and 1 = 0


    and p.category_id = #{categoryId}
     and p.name like concat('%', #{name}, '%')
     and p.platform_type = #{platformType}
     and p.is_default = #{isDefault}
     and p.status = #{status}

order by p.is_default desc, p.create_time desc

