update gb_ai_platforms
site_id = #{siteId}, name = #{name}, platform_type = #{platformType}, api_endpoint = #{baseUrl}, api_key = #{apiKey}, api_secret = #{organizationId}, model_name = #{defaultModel}, available_models = #{availableModels}, category_id = #{categoryId}, config = #{proxyConfig}, max_tokens = #{maxTokens}, temperature = #{temperature}, rate_limit = #{rateLimitPerMinute}, cost_per_1k_tokens = #{costPer1kTokens}, is_default = #{isDefault}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where id = #{id}
